        });

        shopInventory.Add(new ShopItem
        {
            itemId = "gold_pack_large",
            itemName = "Large Gold Pack (2000g)",
            basePrice = 0,
            currentPrice = 0,
            itemType = ItemType.CurrencyPack,
            effectValue = 2000f,
            isPremium = true,
            premiumPrice = 150
        });

        RecalculatePrices();
    }

    // WARNING: Client-side price calculation - acceptable for single-player.
    // For IAP items, actual purchase validation should go through platform (Google Play / App Store).
    public void RecalculatePrices()
    {
        foreach (var item in shopInventory)
        {
            if (!item.isPremium)
            {
                float discount = 1f - (discountPercent / 100f);
                item.currentPrice = Mathf.Max(1, Mathf.RoundToInt(item.basePrice * discount));
            }
        }
    }

    public int GetDynamicPrice(ShopItem item)
    {
        if (item.isPremium)
            return item.premiumPrice;

        int playerLevel = PlayerManager.Instance.playerStats.playerLevel;
        float levelMultiplier = 1f + (playerLevel - 1) * 0.05f;
        float discount = 1f - (discountPercent / 100f);

        int dynamicPrice = Mathf.Max(1, Mathf.RoundToInt(item.basePrice * levelMultiplier * discount));
        return dynamicPrice;
    }

    public bool PurchaseItem(string itemId)
    {
        ShopItem item = shopInventory.Find(i => i.itemId == itemId);
        if (item == null)
        {
            OnPurchaseFailed?.Invoke("Item not found: " + itemId);
            return false;
        }

        if (item.isPremium)
        {
            return PurchaseWithPremiumCurrency(item);
        }
        else
        {
            return PurchaseWithCurrency(item);
        }
    }

    private bool PurchaseWithCurrency(ShopItem item)
    {
        int price = GetDynamicPrice(item);

        if (PlayerManager.Instance.SpendCurrency(price))
        {
            ApplyItemEffect(item);
            PlayerManager.Instance.ownedItems.Add(item);
            OnItemPurchased?.Invoke(item);
            PlayerManager.Instance.SavePlayerData();
            Debug.Log($"Purchased {item.itemName} for {price} gold.");
            return true;
        }
        else
        {
            OnPurchaseFailed?.Invoke($"Not enough gold to buy {item.itemName}. Need {price}, have {PlayerManager.Instance.playerStats.currency}.");
            return false;
        }
    }

    private bool PurchaseWithPremiumCurrency(ShopItem item)
    {
        if (PlayerManager.Instance.SpendPremiumCurrency(item.premiumPrice))
        {
            ApplyItemEffect(item);
            PlayerManager.Instance.ownedItems.Add(item);
            OnItemPurchased?.Invoke(item);
            PlayerManager.Instance.SavePlayerData();
            Debug.Log($"Purchased {item.itemName} for {item.premiumPrice} gems.");
            return true;
        }
        else
        {
            OnPurchaseFailed?.Invoke($"Not enough gems to buy {item.itemName}. Need {item.premiumPrice}, have {PlayerManager.Instance.playerStats.premiumCurrency}.");
            return false;
        }
    }

    private void ApplyItemEffect(ShopItem item)
    {
        PlayerManager pm = PlayerManager.Instance;

        switch (item.itemType)
        {
            case ItemType.HealthPotion:
                pm.Heal(item.effectValue);
                break;

            case ItemType.Weapon:
                pm.playerStats.baseAttack += item.effectValue;
                pm.bonusAttackPercent += item.effectValue;
                break;

            case ItemType.Armor:
                pm.playerStats.baseDefense += item.effectValue;
                pm.damageReductionPercent += item.effectValue;
                break;

            case ItemType.CurrencyPack:
                pm.AddCurrency(Mathf.RoundToInt(item.effectValue));
                break;

            case ItemType.PremiumCurrencyPack:
                pm.AddPremiumCurrency(Mathf.RoundToInt(item.effectValue));
                break;
        }
    }

    public void SetDiscount(float percent)
    {
        discountPercent = Mathf.Clamp(percent, 0f, 90f);
        RecalculatePrices();
    }
}

