public class DamageCalculator : MonoBehaviour
{
    // WARNING: All damage calculations are client-side.
    // This is acceptable for single-player but would be exploitable in multiplayer.

    public static float CalculateElementalDamage(float baseDamage, ElementType attackElement, ElementType defenseElement)
    {
        float multiplier = GetElementalMultiplier(attackElement, defenseElement);
        return baseDamage * multiplier;
    }

    public static float GetElementalMultiplier(ElementType attack, ElementType defense)
    {
        // Fire > Nature > Water > Fire
        if (attack == ElementType.Fire && defense == ElementType.Nature) return 1.5f;
        if (attack == ElementType.Nature && defense == ElementType.Water) return 1.5f;
        if (attack == ElementType.Water && defense == ElementType.Fire) return 1.5f;

        // Reverse - weak
        if (attack == ElementType.Fire && defense == ElementType.Water) return 0.5f;
        if (attack == ElementType.Nature && defense == ElementType.Fire) return 0.5f;
        if (attack == ElementType.Water && defense == ElementType.Nature) return 0.5f;

        // Light <> Dark
        if (attack == ElementType.Light && defense == ElementType.Dark) return 1.75f;
        if (attack == ElementType.Dark && defense == ElementType.Light) return 1.75f;

        return 1.0f;
    }

    public static float CalculateSkillDamage(float baseAttack, float skillMultiplier, float skillLevel, float targetDefense)
    {
        float rawDamage = baseAttack * skillMultiplier * (1f + (skillLevel - 1f) * 0.15f);
        float defenseReduction = targetDefense / (targetDefense + 100f);
        float finalDamage = rawDamage * (1f - defenseReduction);

        // Random variance ±10%
        float variance = UnityEngine.Random.Range(0.9f, 1.1f);
        finalDamage *= variance;

        return Mathf.Max(1f, finalDamage);
    }

    public static DamageResult CalculateFullDamage(
        float attackerBaseAttack,
        float attackerBonusPercent,
        float attackerCritChance,
        float attackerCritMultiplier,
        float skillMultiplier,
        float skillLevel,
        ElementType attackElement,
        float defenderDefense,
        float defenderDamageReduction,
        ElementType defenseElement)
    {
        DamageResult result = new DamageResult();

        float totalAttack = attackerBaseAttack * (1f + attackerBonusPercent / 100f);
        float rawDamage = totalAttack * skillMultiplier * (1f + (skillLevel - 1f) * 0.15f);

        // Critical hit
        result.isCritical = UnityEngine.Random.value <= attackerCritChance;
        if (result.isCritical)
        {
            rawDamage *= attackerCritMultiplier;
        }

        // Elemental
        float elementalMultiplier = GetElementalMultiplier(attackElement, defenseElement);
        rawDamage *= elementalMultiplier;
        result.elementalMultiplier = elementalMultiplier;

        // Defense
        float effectiveDefense = defenderDefense * (1f + defenderDamageReduction / 100f);
        float defenseReduction = effectiveDefense / (effectiveDefense + 100f);
        float finalDamage = rawDamage * (1f - defenseReduction);

        // Variance
        float variance = UnityEngine.Random.Range(0.9f, 1.1f);
        finalDamage *= variance;

        result.finalDamage = Mathf.Max(1f, finalDamage);
        result.rawDamage = rawDamage;

        return result;
    }
}

public struct DamageResult
{
    public float finalDamage;
    public float rawDamage;
    public bool isCritical;
    public float elementalMultiplier;
}

public enum ElementType
{
    None,
    Fire,
    Water,
    Nature,
    Light,
    Dark
}

public class EnemyController : MonoBehaviour
{
    public string enemyName = "Enemy";
    public float maxHealth = 50f;
    public float currentHealth = 50f;
    public float attackPower = 10f;
    public float defense = 5f;
    public float attackCooldown = 2f;
    public int currencyDropMin = 10;
    public int currencyDropMax = 50;
    public int experienceReward = 25;
    public ElementType elementType = ElementType.None;

    public event Action<float> OnEnemyHealthChanged;
    public event Action OnEnemyDied;

    private float attackTimer;

    private void Start()
    {
        currentHealth = maxHealth;
        attackTimer = attackCooldown;
    }

    private void Update()
    {
        attackTimer -= Time.deltaTime;
        if (attackTimer <= 0f)
        {
            AttackPlayer();
            attackTimer = attackCooldown;
        }
    }

    public void TakeDamage(float damage)
    {
        currentHealth -= damage;
        currentHealth = Mathf.Clamp(currentHealth, 0f, maxHealth);

        OnEnemyHealthChanged?.Invoke(currentHealth);

        if (currentHealth <= 0f)
        {
            Die();
        }
    }

    private void AttackPlayer()
    {
        if (PlayerManager.Instance != null && PlayerManager.Instance.playerStats.currentHealth > 0f)
        {
            PlayerManager.Instance.TakeDamage(attackPower);
        }
    }

    private void Die()
    {
        int currencyDrop = UnityEngine.Random.Range(currencyDropMin, currencyDropMax + 1);
        PlayerManager.Instance.AddCurrency(currencyDrop);

        OnEnemyDied?.Invoke();
        Debug.Log($"{enemyName} defeated! Dropped {currencyDrop} gold.");

        Destroy(gameObject);
    }
}

public class GameUIManager : MonoBehaviour
{
    public UnityEngine.UI.Text healthText;
    public UnityEngine.UI.Text currencyText;
    public UnityEngine.UI.Text premiumCurrencyText;
    public UnityEngine.UI.Text levelText;
    public UnityEngine.UI.Slider healthSlider;
    public GameObject shopPanel;

    private void Start()
    {
        if (PlayerManager.Instance != null)
        {
            PlayerManager.Instance.OnHealthChanged += UpdateHealthUI;
            PlayerManager.Instance.OnCurrencyChanged += UpdateCurrencyUI;
            PlayerManager.Instance.OnPlayerDied += ShowDeathScreen;
        }

        if (ShopManager.Instance != null)
        {
            ShopManager.Instance.OnItemPurchased += OnItemBought;
            ShopManager.Instance.OnPurchaseFailed += OnPurchaseFailed;
        }

        UpdateAllUI();
    }

    private void OnDestroy()
    {
        if (PlayerManager.Instance != null)
        {
            PlayerManager.Instance.OnHealthChanged -= UpdateHealthUI;
            PlayerManager.Instance.OnCurrencyChanged -= UpdateCurrencyUI;
            PlayerManager.Instance.OnPlayerDied -= ShowDeathScreen;
        }

        if (ShopManager.Instance != null)
        {
            ShopManager.Instance.OnItemPurchased -= OnItemBought;
            ShopManager.Instance.OnPurchaseFailed -= OnPurchaseFailed;
        }
    }

    public void UpdateAllUI()
    {
        if (PlayerManager.Instance == null) return;

        var stats = PlayerManager.Instance.playerStats;
        UpdateHealthUI(stats.currentHealth);
        UpdateCurrencyUI(stats.currency);

        if (premiumCurrencyText != null)
            premiumCurrencyText.text = $"Gems: {stats.premiumCurrency}";

        if (levelText != null)
            levelText.text = $"Level: {stats.playerLevel}";
    }

    private void UpdateHealthUI(float currentHealth)
    {
        if (PlayerManager.Instance == null) return;

        var stats = PlayerManager.Instance.playerStats;

        if (healthText != null)
            healthText.text = $"HP: {Mathf.CeilToInt(currentHealth)} / {Mathf.CeilToInt(stats.maxHealth)}";

        if (healthSlider != null)
        {
            healthSlider.maxValue = stats.maxHealth;
            healthSlider.value = currentHealth;
        }
    }

    private void UpdateCurrencyUI(int currency)
    {
        if (currencyText != null)
            currencyText.text = $"Gold: {currency}";
    }

    public void ToggleShop()
    {
        if (shopPanel != null)
            shopPanel.SetActive(!shopPanel.activeSelf);
    }

    public void OnBuyButtonClicked(string itemId)
    {
        ShopManager.Instance?.PurchaseItem(itemId);
    }

    public void OnBuyGemsClicked(string productId)
    {
        IAPManager.Instance?.PurchaseGemPack(productId);
    }

    private void OnItemBought(ShopItem item)
    {
        UpdateAllUI();
        Debug.Log($"UI: Successfully purchased {item.itemName}!");
    }

    private void OnPurchaseFailed(string reason)
    {
        Debug.Log($"UI: Purchase failed - {reason}");
    }

    private void ShowDeathScreen()
    {
        Debug.Log("UI: Showing death screen.");
    }
}